import subprocess
import os

def generate_requirements_txt():
    """Generate a requirements.txt file with hashes for all dependencies."""
    try:
        subprocess.run(['pip-compile', '--generate-hashes', '--output-file', 'requirements.txt'], check=True)
        print("requirements.txt generated successfully with hashes.")
    except subprocess.CalledProcessError as e:
        print(f"Error generating requirements.txt: {e}")

def update_requirements_txt():
    """Update the requirements.txt file with the latest versions of dependencies."""
    try:
        subprocess.run(['pip-compile', '--upgrade', '--generate-hashes', '--output-file', 'requirements.txt'], check=True)
        print("requirements.txt updated successfully with latest versions and hashes.")
    except subprocess.CalledProcessError as e:
        print(f"Error updating requirements.txt: {e}")

def generate_poetry_lock():
    """Generate a poetry.lock file for all dependencies."""
    try:
        subprocess.run(['poetry', 'lock'], check=True)
        print("poetry.lock generated successfully.")
    except subprocess.CalledProcessError as e:
        print(f"Error generating poetry.lock: {e}")

def update_poetry_lock():
    """Update the poetry.lock file with the latest versions of dependencies."""
    try:
        subprocess.run(['poetry', 'update'], check=True)
        print("poetry.lock updated successfully with latest versions.")
    except subprocess.CalledProcessError as e:
        print(f"Error updating poetry.lock: {e}")

def main():
    """Main function to manage dependency lock files."""
    if not os.path.exists('pyproject.toml'):
        print("pyproject.toml not found. Using requirements.txt for dependency management.")
        generate_requirements_txt()
        update_requirements_txt()
    else:
        print("pyproject.toml found. Using Poetry for dependency management.")
        generate_poetry_lock()
        update_poetry_lock()

if __name__ == "__main__":
    main()